import java.util.Scanner;

public class SafeBufferCopy {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String input = scanner.next();

        // Assuming the input is limited to 10 characters
        char[] buffer = new char[10];

        // Copying user input into the buffer with bounds checking
        int length = Math.min(input.length(), buffer.length);
        System.arraycopy(input.toCharArray(), 0, buffer, 0, length);

        System.out.println("Your name is: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
